932: // registerStorageReadinessCheck registers the readiness checks for all underlying storages
933: // for a given APIGroup.
934: func (s *GenericAPIServer) registerStorageReadinessCheck(groupName string, apiGroupInfo *APIGroupInfo) {
935: 	for version, storageMap := range apiGroupInfo.VersionedResourcesStorageMap {
936: 		for resource, storage := range storageMap {
937: 			if withReadiness, ok := storage.(rest.StorageWithReadiness); ok {
938: 				gvr := metav1.GroupVersionResource{
939: 					Group:    groupName,
940: 					Version:  version,
941: 					Resource: resource,
942: 				}
943: 				s.StorageReadinessHook.RegisterStorage(gvr, withReadiness)
944: 			}
945: 		}
946: 	}
947: }
